INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2023/09/22 14:59:59", 1, 2, "いらっしゃいませっ♪\nキャラバンコインを使って\n買い物ができますよっ！", 2002, -470.0, 126401, "2023/06/30 12:00:00", 1, 1, 1.47, 0.0, 10001, "クローチェ");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2023/09/22 14:59:59", 2, 1, "素敵な品が揃ってるので\nたーっくさん買っていって\nくださいねっ♪", 2002, -470.0, 126401, "2023/06/30 12:00:00", 1, 2, 2.15, 0.0, 10002, "クローチェ");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2023/09/22 14:59:59", 2, 2, "ショップへようこそ\nキャラバンコインはこちら\nで買い物に使えますよ", 2002, -470.0, 126501, "2023/06/30 12:00:00", 1, 1, 0.0, 0.0, 10003, "ライラエル");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2023/09/22 14:59:59", 1, 1, "こちらのショップで\n買い物をして、素敵な\n旅を楽しんでくださいね", 2002, -470.0, 126501, "2023/06/30 12:00:00", 1, 2, 0.0, 0.0, 10004, "ライラエル");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2023/12/22 14:59:59", 2, 2, "いらっしゃいませ\nキャラバンコインを使って\nお買い物ができますよ", 2002, -470.0, 127702, "2023/09/15 15:00:00", 2, 1, 0.0, 0.0, 10005, "リンド");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2023/12/22 14:59:59", 2, 2, "ショップの掃除は完璧です\n姫さま直営のお店として\n当然のことですから", 2002, -470.0, 127702, "2023/09/15 15:00:00", 2, 2, 0.0, 0.0, 10006, "リンド");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2023/12/22 14:59:59", 1, 1, "ショップへようこそ\nキャラバンコインと品物を\n交換できるんで、よければ", 2002, -470.0, 127802, "2023/09/15 15:00:00", 2, 1, 0.0, 0.0, 10007, "ヴルム");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2023/12/22 14:59:59", 2, 1, "なんで店番なんか…\nま、やりますけど\n好きな品物をどうぞ", 2002, -470.0, 127802, "2023/09/15 15:00:00", 2, 2, 6.5, 0.0, 10008, "ヴルム");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2024/03/22 14:59:59", 2, 1, "──いらっしゃいませ\n買い物しても、いいですよ\nキャラバンコインがあれば", 2002, -470.0, 129602, "2023/12/15 15:00:00", 3, 1, 0.0, 0.0, 10009, "アネモネ");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2024/03/22 14:59:59", 2, 1, "──もっと笑顔がほしい？\nいくらコインを積まれても\n売れない物はありますから", 2002, -470.0, 129602, "2023/12/15 15:00:00", 3, 2, 0.0, 0.0, 10010, "アネモネ");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2024/03/22 14:59:59", 1, 1, "ようこそおいでなんし\nキャラバンコインをこちら\nで交換して進ぜんしょう", 2002, -470.0, 129701, "2023/12/15 15:00:00", 3, 1, 0.0, 0.0, 10011, "ネフィ=ネラ");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2024/03/22 14:59:59", 2, 1, "ところで、お前さまは\nいくらで贖えるのか喃？\n──フフ、冗談でありんす", 2002, -470.0, 129701, "2023/12/15 15:00:00", 3, 2, 6.2, 0.0, 10012, "ネフィ=ネラ");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2024/06/22 14:59:59", 3, 5, "い、いらっしゃいませっ！\n…くっ…このあたくし様が\n店番なんて…屈辱ですわっ", 2002, -470.0, 130301, "2024/03/15 15:00:00", 4, 1, 3.1, 0.0, 10013, "カノン");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2024/06/22 14:59:59", 3, 2, "あら、あたくしをご所望？\nお生憎様、そんな小銭では\n…買えちゃうんですの！？", 2002, -470.0, 130301, "2024/03/15 15:00:00", 4, 2, 6.15, 0.0, 10014, "カノン");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2024/06/22 14:59:59", 2, 2, "いらっしゃいませ～♪\nきゃらばんこいん？を\n交換できるんだってー", 2002, -470.0, 130401, "2024/03/15 15:00:00", 4, 1, 0.0, 0.0, 10015, "ナーナ");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2024/06/22 14:59:59", 2, 1, "甘いのくれたら、\nお礼にナーナの拾った\n松ぼっくりあげちゃうよ！", 2002, -470.0, 130401, "2024/03/15 15:00:00", 4, 2, 3.35, 0.0, 10016, "ナーナ");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2024/09/22 14:59:59", 1, 1, "ショップへようこそ\nこの鳳凰が、皆さんに\n祝福を差し上げましょう", 2002, -470.0, 130502, "2024/06/15 15:00:00", 5, 1, 0.0, 0.0, 10017, "ホウオウ");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2024/09/22 14:59:59", 2, 1, "ほーちゃんと呼ぶ権利は\n売っていませんよ？\n騎士さんへの、特別です！", 2002, -470.0, 130502, "2024/06/15 15:00:00", 5, 2, 3.18, 0.0, 10018, "ホウオウ");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2024/09/22 14:59:59", 4, 4, "うﾞぇぇえんっ！まﾞだごの\n格好になっぢゃいまじだ！\n寄付をお願いじまず～っ！", 2002, -470.0, 130503, "2024/06/15 15:00:00", 5, 3, 0.0, 0.0, 10019, "ホウオウ");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2024/09/22 14:59:59", 1, 2, "おっすー♪\nなんでも交換してけー\nカリザきゅん以外で", 2002, -470.0, 123301, "2024/06/15 15:00:00", 5, 1, 4.9, 0.0, 10020, "ネア");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2024/09/22 14:59:59", 1, 2, "ところで、騎士きゅんは\nおいくら万ルピ？\nジョーダンぬ・き・で♡", 2002, -470.0, 123301, "2024/06/15 15:00:00", 5, 2, 4.8, 0.0, 10021, "ネア");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2024/12/22 14:59:59", 3, 1, "ケッ、なんでオレ様が店番\nなんざ…って来んなキイロ\nオレは売りモンじゃねー！", 2002, -470.0, 133301, "2024/09/15 15:00:00", 6, 1, 4.922, 0.0, 10022, "カリザ");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2024/12/22 14:59:59", 3, 5, "い、言わなきゃダメか？\n「…いらっしゃいませ…」\nクソッ、笑うんじゃねー！", 2002, -470.0, 133301, "2024/09/15 15:00:00", 6, 2, 9.638, 0.0, 10023, "カリザ");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2024/12/22 14:59:59", 1, 2, "ショップへようこそ～\nネラさまの腹心…的な私が\n店番させていただきま～す", 2002, -470.0, 133401, "2024/09/15 15:00:00", 6, 1, 2.88, 0.0, 10024, "ミーア");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2024/12/22 14:59:59", 5, 1, "私の抜け殻とか、\n需要ありますかね～…\nって冗談ですよ、冗談！", 2002, -470.0, 133401, "2024/09/15 15:00:00", 6, 2, 4.818, 0.0, 10025, "ミーア");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2025/03/22 14:59:59", 2, 1, "へい、らっしゃい\nさ、騎士氏。冥土の土産は\nなにがいいですか？", 2002, -470.0, 133002, "2024/12/15 15:00:00", 7, 1, 1.78, 0.0, 10026, "グレイス");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2025/03/22 14:59:59", 1, 7, "商品をお買い上げ毎に\nグレイスちゃんポイントを\n差し上げます。嘘ですが", 2002, -470.0, 133002, "2024/12/15 15:00:00", 7, 2, 6.15, 0.0, 10027, "グレイス");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2025/03/22 14:59:59", 6, 2, "ようこそいらっしゃいませ\n…接客とは、このような\n振舞で宜しいでしょうか？", 2002, -470.0, 133102, "2024/12/15 15:00:00", 7, 1, 4.28, 0.0, 10028, "ヴァイオレット");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2025/03/22 14:59:59", 1, 1, "じめじめした商品は\nございませんので\n安心してお買い求め下さい", 2002, -470.0, 133102, "2024/12/15 15:00:00", 7, 2, 0.0, 0.0, 10029, "ヴァイオレット");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2025/06/23 14:59:59", 2, 1, "いらっしゃいましぇでしゅ\n何をお求めでしゅか？\nたこ焼きもありましゅよ！", 2002, -470.0, 136902, "2025/03/15 15:00:00", 8, 1, 5.53, 0.0, 10030, "ルルィ");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2025/06/23 14:59:59", 9, 7, "そのコイン…ピカピカで、\n集めたくなっちゃいましゅ\nタコ釣られされちゃう～…", 2002, -470.0, 136902, "2025/03/15 15:00:00", 8, 2, 6.05, 0.0, 10031, "ルルィ");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2025/06/23 14:59:59", 2, 1, "姫のご友人ならば\n礼儀を尽くすのが爺の務め\nさ、望みの物を言いたまえ", 2002, -470.0, 137001, "2025/03/15 15:00:00", 8, 1, 0.0, 0.0, 10032, "デュラン");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2025/06/23 14:59:59", 2, 1, "キャラバンコインではなく\n首で支払って貰えんかのぅ\n…冗談であるぞ？", 2002, -470.0, 137001, "2025/03/15 15:00:00", 8, 2, 0.0, 0.0, 10033, "デュラン");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2025/09/23 14:59:59", 2, 2, "おう\n好きなもん持ってきな", 2002, -470.0, 135902, "2025/06/16 15:00:00", 9, 1, 0.0, 0.0, 10034, "サツキ");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2025/09/23 14:59:59", 1, 6, "宵越しの銭を持つような\n野暮いマネぁしくさんな\nツキが落ちてもしらねぇぜ", 2002, -470.0, 135902, "2025/06/16 15:00:00", 9, 2, 4.935, 0.0, 10035, "サツキ");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2025/09/23 14:59:59", 2, 5, "ら、ら、らっしゃっせ…\nなんかほしいもん、ある？\nか、かき氷とか、ど…？", 2002, -470.0, 135802, "2025/06/16 15:00:00", 9, 1, 7.441, 0.0, 10036, "ユキノ");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2025/09/23 14:59:59", 7, 7, "そ、そんな見ねぇで…\nあては、売りもんじゃ\nねぇよ…？", 2002, -470.0, 135802, "2025/06/16 15:00:00", 9, 2, 0.0, 0.0, 10037, "ユキノ");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2025/12/22 14:59:59", 2, 2, "クルルをお求めですかっ？\nそれならお礼に、こちらの\n宝石もどうぞですよ～♪", 2002, -470.0, 130901, "2025/09/16 15:00:00", 10, 1, 2.295, 0.0, 10038, "クルル");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2025/12/22 14:59:59", 1, 6, "はっ！　ヒーローさんから\nお代なんて頂けないです！\nどうぞどうぞ…え、ダメ？", 2002, -470.0, 130901, "2025/09/16 15:00:00", 10, 2, 6.281, 0.0, 10039, "クルル");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2025/12/22 14:59:59", 2, 1, "よぅ！　今日の俺さまは\n門番じゃなく、店番だぜ\nメモピ～スフィア～てな！", 2002, -470.0, 137701, "2025/09/16 15:00:00", 10, 1, 5.549, 0.0, 10040, "ヴォルガーノ");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2025/12/22 14:59:59", 3, 6, "…リマさんのブロマイド？\n買い取るに決まってらぁ！\nなんでも持ってけ泥棒っ！", 2002, -470.0, 137701, "2025/09/16 15:00:00", 10, 2, 2.64, 0.0, 10041, "ヴォルガーノ");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2026/03/23 11:59:59", 7, 4, "こ、この格好は…ヴルムが\n集客効果があると言って…\n…本当でしょうか？", 2002, -470.0, 132801, "2025/12/15 15:00:00", 11, 1, 7.642, 0.0, 10042, "ライラエル");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2026/03/23 11:59:59", 1, 1, "この我に店番させるとは…\n全て買わねば許さぬぞ\n我が国庫に貢献するが良い", 2002, -470.0, 132802, "2025/12/15 15:00:00", 11, 2, 0.0, 0.0, 10043, "ライラエル");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2026/03/23 11:59:59", 1, 1, "アナライズっ！\n本日のオススメ商品は～…\nこちらですっ♪", 2002, -470.0, 134502, "2025/12/15 15:00:00", 11, 1, 0.0, 0.0, 10044, "クローチェ");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2026/03/23 11:59:59", 2, 1, "ギガンティックローチェ、\nおひとついかがですかっ？\n格納庫用意して下さいねっ", 2002, -470.0, 134501, "2025/12/15 15:00:00", 11, 2, 3.72, 0.0, 10045, "クローチェ");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2026/06/22 11:59:59", 2, 1, "番頭も、飯事の如き営み\nなれば。愛らしき稚児らで\n千客万来といきませぬか喃", 2002, -470.0, 138201, "2026/03/16 12:00:00", 12, 1, 4.991, 0.0, 10046, "ネフィ＝ネラ");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2026/06/22 11:59:59", 1, 4, "国を営むに金子は必須也…\nどうか御恵みくだしゃんせ\n誠心を以て報恩致しまする", 2002, -470.0, 138201, "2026/03/16 12:00:00", 12, 2, 3.877, 0.0, 10047, "ネフィ＝ネラ");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2026/06/22 11:59:59", 4, 6, "あぅっ…！　天井が低くて\n頭をぶつけてしまって…\nわたしが、大きいだけ…？", 2002, -470.0, 136001, "2026/03/16 12:00:00", 12, 1, 1.71, 0.0, 10048, "アラクネ");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2026/06/22 11:59:59", 5, 2, "いらっしゃいませ騎士さま\nくつろいでいって下さいね\nもし叶うなら…永遠に…", 2002, -470.0, 136001, "2026/03/16 12:00:00", 12, 2, 5.32, 0.0, 10049, "アラクネ");
